const response = $input.first().json;
const refunds = response.data || response.refund_requests || [];

if (!Array.isArray(refunds) || refunds.length === 0) return [];

const lines = refunds.map(r =>
  `\u2022 ${r.customer_email || r.email || 'N/A'} - ${r.product_name || r.product || 'N/A'} (${r.amount ? r.amount/100 : '?'} ${String(r.currency || '').toUpperCase()})`
).join('\n');

const msg = `\u26A0\uFE0F *Pending refund requests: ${refunds.length}*\n\n${lines}\n\n\u{1F449} Handle them in the Sellf admin panel`;

return [{ json: { message: msg, count: refunds.length } }];
